use strict;
use warnings;
use CAM::PDF;

# Path to the PDF file
my $pdf_file = 'path/to/your/pdffile.pdf';

# Open the PDF
my $pdf = CAM::PDF->new($pdf_file);

# Function to extract metadata (author, date)
sub extract_metadata {
    my ($pdf) = @_;
    my $info = $pdf->getInfo();
    my $author = $info->{'/Author'};
    my $date = $info->{'/ModDate'};

    return ($author, $date);
}

# Function to extract tables from the PDF
sub extract_tables {
    my ($pdf) = @_;
    my $num_pages = $pdf->numPages();
    my @tables;

    for (my $page = 1; $page <= $num_pages; $page++) {
        my $text = $pdf->getPageText($page);
        # Regex to identify potential tables (this is a simple example)
        if ($text =~ /Table\s+\d+/) {
            push @tables, $text;
        }
    }

    return @tables;
}

# Extract metadata
my ($author, $date) = extract_metadata($pdf);
print "Author: $author\n";
print "Date: $date\n";

# Extract tables
my @tables = extract_tables($pdf);
foreach my $table (@tables) {
    print "Table: $table\n";
}
